/**
 * @param {number[]} nums
 * @param {number[][]} edges
 * @return {number}
 */
function solve(nums, edges) {
    const n = nums.length;
    const adj = Array(n).fill(0).map(() => []);

    // Build adjacency list for the full graph
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;

    // Iterate over all non-empty subsets of nodes (represented by bitmasks from 1 to 2^n - 1)
    for (let mask = 1; mask < (1 << n); mask++) {
        // 1. Check the sum of values (parity)
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
            }
        }

        // Condition 2: Sum of node values must be even
        if (sum % 2 !== 0) {
            continue;
        }

        // 2. Check connectivity of the induced subgraph

        // Identify nodes in the subset s
        const subsetNodes = [];
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subsetNodes.push(i);
            }
        }

        if (subsetNodes.length === 0) continue; // Should not happen due to loop starting at 1

        // Use BFS or DFS to check connectivity within the induced subgraph
        const startNode = subsetNodes[0];
        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 0;

        while (queue.length > 0) {
            const u = queue.shift();
            visitedCount++;

            // Check neighbors of u in the original graph
            for (const v of adj[u]) {
                // Check if v is in the subset s AND v has not been visited
                if (((mask >> v) & 1) && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                }
            }
        }

        // Condition 1: The induced subgraph must be connected
        // If the number of visited nodes equals the total number of nodes in the subset, it is connected.
        if (visitedCount === subsetNodes.length) {
            count++;
        }
    }

    return count;
}

